import pathlib
import urllib.parse
import time
import textwrap
import shutil
import yaml
import json

from python_on_whales import docker

from Deadline.open_studio_landscapes.constants import *
from Deadline.open_studio_landscapes.utils import *

from dagster import (
    AssetIn,
    AssetExecutionContext,
    asset,
    Output,
    AssetMaterialization,
    MetadataValue,
)


GROUP = "Dagster"
KEY = "Dagster"

asset_header = {
    "group_name": GROUP,
    "key_prefix": [KEY],
    "compute_kind": "python"
}


@asset(
    **asset_header,
    ins={
        "env_base": AssetIn(),
    },
)
def env(
        context: AssetExecutionContext,
        env_base: dict,
) -> dict:

    # @formatter:off
    _env = {
        "DAGSTER_DEV_PORT_HOST": "3003",
        "DAGSTER_DEV_PORT_CONTAINER": "3006",
        "DAGSTER_ROOT": "/dagster",
        "DAGSTER_HOME": "/dagster/materializations",
        "DAGSTER_HOST": "0.0.0.0",
        "DAGSTER_WORKSPACE": "/dagster/workspace.yaml",
    }
    # @formatter:on

    env_base.update(_env)

    env_json = pathlib.Path(
        env_base["DOT_LANDSCAPES"],
        env_base.get("LANDSCAPE", "default"),
        "third_party",
        *context.asset_key.path,
        f"{'__'.join(context.asset_key.path)}.json",
    )

    env_json.parent.mkdir(parents=True, exist_ok=True)

    with open(env_json, "w") as fw:
        json.dump(
            obj=_env.copy(),
            fp=fw,
            indent=2,
            ensure_ascii=True,
            sort_keys=True,
        )

    yield Output(env_base)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            "__".join(context.asset_key.path): MetadataValue.json(env_base),
            "json": MetadataValue.path(env_json),
        },
    )


