@asset(
    **asset_header,
    ins={
        "env": AssetIn(
            key_prefix=[KEY],
        ),
        "build_base_image": AssetIn(),
        "pip_packages": AssetIn(
            key_prefix=[KEY],
        ),
    },
)
def build(
        context: AssetExecutionContext,
        env: dict,
        build_base_image: str,
        pip_packages: list,
) -> str:
    """
    """

    docker_file = pathlib.Path(
        env["DOT_LANDSCAPES"],
        env.get("LANDSCAPE", "default"),
        "Dockerfiles",
        *context.asset_key.path,
        "Dockerfile",
    )

    tags = [
        f"{env.get('IMAGE_PREFIX')}/{'__'.join(context.asset_key.path).lower()}:latest",
        f"{env.get('IMAGE_PREFIX')}/{'__'.join(context.asset_key.path).lower()}:{env.get('LANDSCAPE', str(time.time()))}",
    ]

    pip_install_str: str = get_pip_install_str(
        pip_install_packages=pip_packages,
    )

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        # {dagster_url}
        FROM {parent_image} AS {image_name}
        LABEL authors="{AUTHOR}"
        
        {pip_install_str}
        
        WORKDIR {DAGSTER_ROOT}
        COPY ./payload/workspace.yaml .
        
        WORKDIR {DAGSTER_HOME}
        COPY ./payload/dagster.yaml .
        
        WORKDIR {DAGSTER_ROOT}
        
        ENTRYPOINT ["dagster", "dev"]
        CMD []
    """).format(
        pip_install_str=pip_install_str.format(
            **env,
        ),
        auto_generated=f"AUTO-GENERATED by Dagster Asset {'__'.join(context.asset_key.path)}",
        dagster_url=urllib.parse.quote(f"http://localhost:3000/asset-groups/{'%2F'.join(context.asset_key.path)}", safe=":/%"),
        image_name="__".join(context.asset_key.path).lower(),
        parent_image=build_base_image,
        **env,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    payload = docker_file.parent / "payload"
    payload.mkdir(parents=True, exist_ok=True)

    # workspace.yaml
    shutil.copy(
        src=pathlib.Path(
            env["CONFIGS_ROOT"],
            "dagster",
            "config",
            "workspace.yaml",
        ).expanduser(),
        dst=payload,
    )

    # dagster.yaml
    shutil.copy(
        src=pathlib.Path(
            env["CONFIGS_ROOT"],
            "dagster",
            "config",
            "materializations",
            "dagster.yaml",
        ).expanduser(),
        dst=payload,
    )

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            "__".join(context.asset_key.path): MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env": MetadataValue.json(env),
        },
    )


@asset(
    **asset_header,
    ins={
        "env": AssetIn(
            key_prefix=[KEY],
        ),
        "build": AssetIn(
            key_prefix=[KEY],
        ),
    },
)
def compose(
        context: AssetExecutionContext,
        env: dict,
        build: str,
) -> dict:
    """
    """

    docker_dict = {
        "services": {
            "dagster": {
                "container_name": "dagster",
                "hostname": "dagster",
                "domainname": env.get("ROOT_DOMAIN"),
                "restart": "always",
                "image": build,
                "networks": [
                    "repository",
                    "mongodb",
                ],
                "environment": {
                    "DAGSTER_HOME": env.get('DAGSTER_HOME'),
                    # Todo
                    #  - [ ] fix hard code here (from deadline-dagster .env)
                    "DAGSTER_DEPLOYMENT": "farm",
                    "DAGSTER_JOBS_IN": "/data/share/nfs/in",
                },
                "healthcheck": {
                    "test": ["CMD", "curl", "-f", f"http://localhost:{env.get('DAGSTER_DEV_PORT_CONTAINER')}"],
                    "interval": "10s",
                    "timeout": "2s",
                    "retries": "3",
                },
                "command": [
                    "--workspace",
                    env.get('DAGSTER_WORKSPACE'),
                    "--host",
                    env.get('DAGSTER_HOST'),
                    "--port",
                    env.get('DAGSTER_DEV_PORT_CONTAINER'),
                ],
                "volumes": [
                    f"{env.get('NFS_ENTRY_POINT')}:{env.get('NFS_ENTRY_POINT')}",
                    f"{env.get('NFS_ENTRY_POINT')}:{env.get('NFS_ENTRY_POINT_LNS')}",
                ],
                "ports": [
                    f"{env.get('DAGSTER_DEV_PORT_HOST')}:{env.get('DAGSTER_DEV_PORT_CONTAINER')}",
                ],
            },
        },
    }

    docker_yaml = yaml.dump(docker_dict)

    yield Output(docker_dict)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            "__".join(context.asset_key.path): MetadataValue.json(docker_dict),
            "docker_dict": MetadataValue.md(f"```json\n{json.dumps(docker_dict, indent=2)}\n```"),
            "docker_yaml": MetadataValue.md(f"```yaml\n{docker_yaml}\n```"),
            "env": MetadataValue.json(env),
        },
    )
